from pathlib import Path
path = Path('src/app/pages/products/products-page.component.scss')
text = path.read_text()
start = text.index('.support-section {')
end = text.index('@media (max-width: 900px)')
new_block = """.support-section {\n  border-radius: 24px;\n  padding: 2rem;\n  background: var(--erp-surface);\n  border: 1px solid var(--erp-border);\n  box-shadow: var(--erp-shadow-soft);\n  display: grid;\n  grid-template-columns: minmax(0, 1.4fr) minmax(260px, 0.9fr);\n  gap: 2rem;\n  align-items: start;\n\n  .support-content {\n    max-width: 100%;\n\n    h3 {\n      font-family: 'Unbounded', 'Space Grotesk', sans-serif;\n      font-size: 1.9rem;\n    }\n  }\n\n  .support-actions {\n    margin-top: 1.5rem;\n  }\n\n  .support-meta {\n    margin-top: 1rem;\n    display: flex;\n    gap: 2rem;\n    flex-wrap: wrap;\n    align-items: baseline;\n\n    .label {\n      display: block;\n      font-size: 0.72rem;\n      letter-spacing: 0.12em;\n      text-transform: uppercase;\n      color: var(--erp-muteds);\n    }\n\n    strong {\n      font-size: 0.95rem;\n      color: var(--erp-ink);\n      display: block;\n    }\n  }\n\n  .support-card {\n    background: #0f172a;\n    color: #fff;\n    border-radius: 18px;\n    padding: 1.4rem;\n    display: flex;\n    flex-direction: column;\n    gap: 1rem;\n    box-shadow: 0 20px 34px rgba(15, 23, 42, 0.35);\n\n    .support-card-header {\n      display: flex;\n      align-items: center;\n      gap: 0.9rem;\n    }\n\n    .tag {\n      font-size: 0.7rem;\n      letter-spacing: 0.2em;\n      text-transform: uppercase;\n      color: rgba(255, 255, 255, 0.6);\n      margin: 0;\n    }\n\n    strong {\n      margin: 0;\n      font-size: 1rem;\n      font-weight: 600;\n    }\n\n    ul {\n      margin: 0;\n      padding: 0;\n      list-style: none;\n      display: flex;\n      flex-direction: column;\n      gap: 0.55rem;\n    }\n\n    li {\n      font-size: 0.85rem;\n      color: rgba(255, 255, 255, 0.85);\n      padding-left: 1rem;\n      position: relative;\n\n      &::before {\n        content: '';\n        width: 6px;\n        height: 6px;\n        border-radius: 50%;\n        background: #5eead4;\n        position: absolute;\n        left: 0;\n        top: 50%;\n        transform: translateY(-50%);\n      }\n    }\n\n    mat-icon {\n      font-size: 1.2rem;\n      color: #5eead4;\n    }\n\n    .support-map {\n      border-radius: 12px;\n      overflow: hidden;\n      border: 1px solid rgba(255, 255, 255, 0.2);\n      margin-top: 0.5rem;\n      height: 160px;\n\n      iframe {\n        width: 100%;\n        height: 100%;\n        border: 0;\n      }\n    }\n  }\n}\n\n"""
path.write_text(text[:start] + new_block + text[end:])
